import { ConfigContext } from "../config.js";
import { Awaitable, ServerPlugin } from "../lib/types.js";
import { FC } from "react";
import { OpenAPIPageProps } from "fumadocs-openapi/ui";
import { OpenAPIServer, Proxy } from "fumadocs-openapi/server";
//#region src/plugins/openapi.d.ts
interface OpenAPIOptions {
  server: OpenAPIServer;
  /** do not add the loader plugin for OpenAPI integration */
  disableLoaderPlugin?: boolean;
  /** must be a client component */
  ClientAPIPage?: FC<OpenAPIPageProps>;
  /**
   * Create proxy server.
   *
   * By default, it will create one when `proxyUrl` is specified in `createOpenAPI()`.
   */
  createProxy?: boolean | (() => Awaitable<Proxy>);
}
/**
 * this will register the OpenAPI adapter & required layout configs.
 */
declare function openapiPlugin<C extends ConfigContext>(options: OpenAPIOptions): ServerPlugin<C>;
//#endregion
export { OpenAPIOptions, openapiPlugin };